#![no_std]
#![no_main]
#![feature(impl_trait_in_assoc_type)]

use cortex_m::peripheral::DWT;
use defmt::*;
use embassy_executor::Spawner;
use embedded_opus::{
    Application, DECODER_STATE_SIZE_STEREO, Decoder, ENCODER_STATE_SIZE_STEREO, Encoder,
};
use {defmt_rtt as _, panic_probe as _};

// 1 second of 440 Hz 48 kHz PCM, generated by build.rs
static PCM_RAW: &[u8] = include_bytes!(concat!(env!("OUT_DIR"), "/bench_pcm.raw"));

const SAMPLE_RATE: i32 = 48_000;
const CHANNELS: usize = 2;
const FRAME_SAMPLES: usize = 960 * CHANNELS; // 20ms stereo

const TARGET_BITRATE: i32 = 64_000;

static mut ENCODER_STATE: [u8; ENCODER_STATE_SIZE_STEREO] = [0; ENCODER_STATE_SIZE_STEREO];
static mut DECODER_STATE: [u8; DECODER_STATE_SIZE_STEREO] = [0; DECODER_STATE_SIZE_STEREO];
static mut PACKET_BUF: [u8; 4000] = [0; 4000];
static mut PCM_OUT: [i16; FRAME_SAMPLES] = [0; FRAME_SAMPLES];

// DWT.CYCCNT ticks at the CPU clock (150 MHz on RP2350)
fn bench<F: FnMut()>(name: &str, iterations: u32, mut body: F) {
    let mut min = u32::MAX;
    let mut max = u32::MIN;
    let mut total: u64 = 0;

    for _ in 0..iterations {
        let start = DWT::cycle_count();
        body();
        let elapsed = DWT::cycle_count().wrapping_sub(start);
        if elapsed < min {
            min = elapsed;
        }
        if elapsed > max {
            max = elapsed;
        }
        total += elapsed as u64;
    }

    let avg = (total / iterations as u64) as u32;
    info!(
        "[bench] {}: min={} avg={} max={} cycles ({} µs avg)",
        name,
        min,
        avg,
        max,
        avg / 150
    );
}

#[embassy_executor::main]
async fn main(_spawner: Spawner) {
    let _p = embassy_rp::init(Default::default());

    let mut core = cortex_m::Peripherals::take().unwrap();
    core.DCB.enable_trace();
    core.DWT.enable_cycle_counter();

    let pcm_samples: &[i16] =
        unsafe { core::slice::from_raw_parts(PCM_RAW.as_ptr() as *const i16, PCM_RAW.len() / 2) };

    let mut encoder = Encoder::new(
        unsafe { &mut *core::ptr::addr_of_mut!(ENCODER_STATE) },
        SAMPLE_RATE,
        CHANNELS,
        Application::Audio,
    )
    .unwrap();
    encoder.set_bitrate(TARGET_BITRATE).unwrap();
    encoder.set_complexity(5).unwrap();

    info!("--- benchmarks start ---");

    let total_frames = pcm_samples.len() / FRAME_SAMPLES;
    let mut frame_idx = 0;

    bench("opus_encode_20ms_stereo_48k_64kbps", 50, || {
        let frame = &pcm_samples[frame_idx * FRAME_SAMPLES..(frame_idx + 1) * FRAME_SAMPLES];
        let packet_buf = unsafe { &mut *core::ptr::addr_of_mut!(PACKET_BUF) };
        encoder.encode(frame, packet_buf).unwrap();
        frame_idx = (frame_idx + 1) % total_frames;
    });

    let packet_len = {
        let frame = &pcm_samples[0..FRAME_SAMPLES];
        let packet_buf = unsafe { &mut *core::ptr::addr_of_mut!(PACKET_BUF) };
        encoder.encode(frame, packet_buf).unwrap()
    };

    let mut decoder = Decoder::new(
        unsafe { &mut *core::ptr::addr_of_mut!(DECODER_STATE) },
        SAMPLE_RATE,
        CHANNELS,
    )
    .unwrap();

    bench("opus_decode_20ms_stereo_48k_64kbps", 50, || {
        let packet = unsafe { &(&*core::ptr::addr_of!(PACKET_BUF))[..packet_len] };
        let pcm_out = unsafe { &mut *core::ptr::addr_of_mut!(PCM_OUT) };
        decoder.decode(packet, pcm_out, false).unwrap();
    });

    info!("--- benchmarks done ---");
}
